ot;MathJax-Span-63&quot; style=&quot;font-size: 70.7%; font-family: MathJax_Main;&quot;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;mfrac&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;mn&amp;gt;10&amp;lt;/mn&amp;gt;&amp;lt;mrow class=&amp;quot;MJX-TeXAtom-ORD&amp;quot;&amp;gt;&amp;lt;mo&amp;gt;&amp;amp;#x3A9;&amp;lt;/mo&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;mn&amp;gt;2&amp;lt;/mn&amp;gt;&amp;lt;/mfrac&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-52-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;span class=&quot;math&quot; id=&quot;MathJax-Span-568&quot; style=&quot;width: 1.908em; display: inline-block;&quot;&gt;&lt;span style=&quot;display: inline-block; position: relative; width: 1.551em; height: 0px; font-size: 120%;&quot;&gt;&lt;span style=&quot;position: absolute; clip: rect(1.074em, 1001.55em, 2.801em, -999.997em); top: -2.199em; left: 0em;&quot;&gt;&lt;span class=&quot;mrow&quot; id=&quot;MathJax-Span-569&quot;&gt;&lt;span class=&quot;mfrac&quot; id=&quot;MathJax-Span-570&quot;&gt;&lt;span style=&quot;display: inline-block; position: relative; width: 1.313em; height: 0px; margin-right: 0.122em; margin-left: 0.122em;&quot;&gt;&lt;span style=&quot;position: absolute; clip: rect(3.336em, 1001.19em, 4.17em, -999.997em); top: -4.402em; left: 50%; margin-left: -0.592em;&quot;&gt;&lt;span class=&quot;mrow&quot; id=&quot;MathJax-Span-571&quot;&gt;&lt;span class=&quot;mn&quot; id=&quot;MathJax-Span-572&quot; style=&quot;font-size: 70.7%; font-family: MathJax_Main;&quot;&gt;10&lt;/span&gt;&lt;span class=&quot;texatom&quot; id=&quot;MathJax-Span-573&quot;&gt;&lt;span class=&quot;mrow&quot; id=&quot;MathJax-Span-574&quot;&gt;&lt;span class=&quot;mo&quot; id=&quot;MathJax-Span-575&quot; style=&quot;font-size: 70.7%; font-family: MathJax_Main;&quot;&gt;&amp;Omega;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;position: absolute; clip: rect(3.336em, 1000.3em, 4.17em, -999.997em); top: -3.568em; left: 50%; margin-left: -0.176em;&quot;&gt;&lt;span class=&quot;mn&quot; id=&quot;MathJax-Span-576&quot; style=&quot;font-size: 70.7%; font-family: MathJax_Main;&quot;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;mfrac&gt;&lt;mrow&gt;&lt;mn&gt;10&lt;/mn&gt;&lt;mrow class=&quot;MJX-TeXAtom-ORD&quot;&gt;&lt;mo&gt;&amp;Omega;&lt;/mo&gt;&lt;/mrow&gt;&lt;/mrow&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/mfrac&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
	&lt;script id=&quot;MathJax-Element-52&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;mfrac&gt;&lt;mrow&gt;&lt;mn&gt;10&lt;/mn&gt;&lt;mrow class=&quot;MJX-TeXAtom-ORD&quot;&gt;&lt;mo&gt;Ω&lt;/mo&gt;&lt;/mrow&gt;&lt;/mrow&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/mfrac&gt;&lt;/math&gt;&lt;/script&gt;
	&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-13&quot; type=&quot;math/tex&quot;&gt; \frac{10 Ω}{2}&lt;/script&gt; होगा, जो &lt;strong&gt;5 &amp;Omega;&lt;/strong&gt; के बराबर है।&lt;/li&gt;
	&lt;li&gt;ऐसा इसलिए है क्योंकि प्रतिरोध &lt;strong&gt;अनुप्रस्थ काट क्षेत्रफल&lt;/strong&gt; के व्युत्क्रमानुपाती होता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;प्रतिरोधकता&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;प्रतिरोधकता&lt;/strong&gt; पदार्थ का एक गुण है जो यह निर्धारित करता है कि वह विद्युत धारा के प्रवाह का कितना दृढ़ता से विरोध करता है।&lt;/li&gt;
		&lt;li&gt;इसे प्रतीक &lt;span 1998=&quot;&quot; aria-hidden=&quot;true&quot; class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&quot; http:=&quot;&quot; id=&quot;MathJax-Element-14-Frame&quot; math=&quot;&quot; nobr=&quot;&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot; www.w3.org=&quot;&quot;&gt;&lt;span class=&quot;math&quot; id=&quot;MathJax-Span-64&quot; style=&quot;width: 0.658em; display: inline-block;&quot;&gt;&lt;span style=&quot;display: inline-block; position: relative; width: 0.539em; height: 0px; font-size: 120%;&quot;&gt;&lt;span style=&quot;position: absolute; clip: rect(1.551em, 1000.54em, 2.562em, -999.997em); top: -2.14em; left: 0em;&quot;&gt;&lt;span class=&quot;mrow&quot; id=&quot;MathJax-Span-65&quot;&gt;&lt;span class=&quot;mi&quot; id=&quot;MathJax-Span-66&quot; style=&quot;font-family: MathJax_Math-italic;&quot;&gt;&amp;rho;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;mi&amp;gt;&amp;amp;#x3C1;&amp;lt;/mi&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-53-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;span class=&quot;math&quot; id=&quot;MathJax-Span-577&quot; style=&quot;width: 0.658em; display: inline-block;&quot;&gt;&lt;span style=&quot;display: inline-block; position: relative; width: 0.539em; height: 0px; font-size: 120%;&quot;&gt;&lt;span style=&quot;position: absolute; clip: rect(1.61em, 1000.54em, 2.622em, -999.997em); top: -2.199em; left: 0em;&quot;&gt;&lt;span class=&quot;mrow&quot; id=&quot;MathJax-Span-578&quot;&gt;&lt;span class=&quot;mi&quot; id=&quot;MathJax-Span-579&quot; style=&quot;font-family: MathJax_Math-italic;&quot;&gt;&amp;rho;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;mi&gt;&amp;rho;&lt;/mi&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
		&lt;script id=&quot;MathJax-Element-53&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;mi&gt;ρ&lt;/mi&gt;&lt;/math&gt;&lt;/script&gt;
		&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-14&quot; type=&quot;math/tex&quot;&gt; \rho&lt;/script&gt; द्वारा दर्शाया जाता है और इसे &lt;strong&gt;ओम-मीटर (&amp;Omega;&amp;middot;m)&lt;/strong&gt; में मापा जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;कम प्रतिरोधकता&lt;/strong&gt; वाले पदार्थ बिजली के अच्छे चालक होते हैं, जबकि &lt;strong&gt;उच्च प्रतिरोधकता&lt;/strong&gt; वाले पदार्थ अच्छे इन्सुलेटर होते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;तार की लंबाई&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;तार की &lt;strong&gt;लंबाई&lt;/strong&gt; उसके प्रतिरोध के समानुपाती होती है।&lt;/li&gt;
		&lt;li&gt;यदि तार की लंबाई &lt;strong&gt;दोगुनी&lt;/strong&gt; हो जाती है, तो प्रतिरोध भी दोगुना हो जाएगा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;अनुप्रस्थ काट क्षेत्रफल&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;तार का &lt;strong&gt;अनुप्रस्थ काट क्षेत्रफल&lt;/strong&gt; उसके प्रतिरोध के व्युत्क्रमानुपाती होता है।&lt;/li&gt;
		&lt;li&gt;यदि अनुप्रस्थ काट क्षेत्रफल &lt;strong&gt;दोगुना&lt;/strong&gt; हो जाता है, तो प्रतिरोध आधा हो जाएगा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Understanding Power, Energy, and Time Relationship&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Definition:&lt;/strong&gt; Power (P) is defined as the rate at which work is done or energy is transferred over time. Energy (E) is the capacity to do work, and time (t) is the duration over which the work is done or the energy is transferred.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Mathematical Relationship:&lt;/strong&gt; The correct equation that relates power, energy, and time is given by:&lt;/p&gt;

&lt;p&gt;P = E / t&lt;/p&gt;

&lt;p&gt;This equation signifies that power is the energy transferred per unit time. In other words, it measures how quickly energy is being used or transferred.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Derivation:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;To understand why P = E / t, let&amp;rsquo;s delve into the fundamental concepts of work, energy, and power:&lt;/p&gt;

&lt;p&gt;&lt;u&gt;Work and Energy:&lt;/u&gt; Work is defined as the force applied over a distance. When this work is done, energy is transferred or converted from one form to another. The SI unit of energy is the joule (J).&lt;/p&gt;

&lt;p&gt;&lt;u&gt;Power:&lt;/u&gt; Power is the rate at which this work is done or energy is transferred. The SI unit of power is the watt (W), where 1 watt is equivalent to 1 joule per second (1 W = 1 J/s).&lt;/p&gt;

&lt;p&gt;&lt;u&gt;Time:&lt;/u&gt; Time is the duration over which the energy transfer or work occurs.&lt;/p&gt;

&lt;p&gt;By combining these concepts, the formula for power (P) can be derived as follows:&lt;/p&gt;

&lt;p&gt;P = E / t&lt;/p&gt;

&lt;p&gt;Here,&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;P is the power (in watts),&lt;/li&gt;
	&lt;li&gt;E is the energy (in joules),&lt;/li&gt;
	&lt;li&gt;t is the time (in seconds).&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Correct Option Analysis:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;The correct option is:&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Option 1:&lt;/strong&gt; P = E / t&lt;/p&gt;

&lt;p&gt;This option accurately represents the relationship between power, energy, and time. It indicates that power is the energy transferred per unit time, which is the correct and standard definition in physics&lt;/p&gt;<br><br>&lt;p&gt;&lt;u&gt;&lt;strong&gt;व्याख्या:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;शक्ति, ऊर्जा और समय के संबंध को समझना&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;परिभाषा:&lt;/strong&gt; शक्ति (P) को उस दर के रूप में परिभाषित किया जाता है जिस पर कार्य किया जाता है या समय के साथ ऊर्जा का स्थानांतरण होता है। ऊर्जा (E) कार्य करने की क्षमता है, और समय (t) वह अवधि है जिस पर कार्य किया जाता है या ऊर्जा का स्थानांतरण होता है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गणितीय संबंध:&lt;/strong&gt; शक्ति, ऊर्जा और समय को जोड़ने वाला सही समीकरण इस प्रकार दिया गया है:&lt;/p&gt;

&lt;p&gt;P = E / t&lt;/p&gt;

&lt;p&gt;यह समीकरण दर्शाता है कि शक्ति प्रति इकाई समय में स्थानांतरित ऊर्जा है। दूसरे शब्दों में, यह मापता है कि ऊर्जा कितनी तेज़ी से उपयोग या स्थानांतरित की जा रही है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;व्युत्पत्ति:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;यह समझने के लिए कि P = E / t क्यों है, आइए कार्य, ऊर्जा और शक्ति की मूल अवधारणाओं में तल्लीन हों:&lt;/p&gt;

&lt;p&gt;&lt;u&gt;कार्य और ऊर्जा:&lt;/u&gt; कार्य को एक दूरी पर लगाए गए बल के रूप में परिभाषित किया जाता है। जब यह कार्य किया जाता है, तो ऊर्जा का स्थानांतरण या रूपांतरण एक रूप से दूसरे रूप में होता है। ऊर्जा की SI इकाई जूल (J) है।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;शक्ति:&lt;/u&gt; शक्ति वह दर है जिस पर यह कार्य किया जाता है या ऊर्जा का स्थानांतरण होता है। शक्ति की SI इकाई वाट (W) है, जहाँ 1 वाट 1 जूल प्रति सेकंड&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(1 W = 1 J/s)&lt;/span&gt; के बराबर है।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;समय:&lt;/u&gt; समय वह अवधि है जिस पर ऊर्जा स्थानांतरण या कार्य होता है।&lt;/p&gt;

&lt;p&gt;इन अवधारणाओं को मिलाकर, शक्ति (P) के लिए सूत्र इस प्रकार व्युत्पन्न किया जा सकता है:&lt;/p&gt;

&lt;p&gt;P = E / t&lt;/p&gt;

&lt;p&gt;यहाँ,&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;P शक्ति (वाट में) है,&lt;/li&gt;
	&lt;li&gt;E ऊर्जा (जूल में) है,&lt;/li&gt;
	&lt;li&gt;t समय (सेकंड में) है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;सही विकल्प विश्लेषण:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;सही विकल्प है:&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विकल्प 1:&lt;/strong&gt; P = E / t&lt;/p&gt;

&lt;p&gt;यह विकल्प शक्ति, ऊर्जा और समय के बीच के संबंध का सही ढंग से प्रतिनिधित्व करता है। यह इंगित करता है कि शक्ति प्रति इकाई समय में स्थानांतरित ऊर्जा है, जो भौतिकी में सही और मानक परिभाषा है।&lt;/p&gt;

&lt;p&gt;The Correct answer is &lt;u&gt;&lt;strong&gt;when the current is perpendicular to the magnetic field&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;When a conductor carrying an electric current is placed in a magnetic field, it experiences a force known as the &lt;strong&gt;Lorentz force&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The magnitude of this force is given by the formula &lt;strong&gt;F = BIL sin(&amp;theta;)&lt;/strong&gt;, where &lt;strong&gt;B&lt;/strong&gt; is the magnetic field strength, &lt;strong&gt;I&lt;/strong&gt; is the current, &lt;strong&gt;L&lt;/strong&gt; is the length of the conductor, and &lt;strong&gt;&amp;theta;&lt;/strong&gt; is the angle between the current and the magnetic field.&lt;/li&gt;
	&lt;li&gt;The force is maximum when the angle &amp;theta; is 90 degrees, i.e., when the current is &lt;strong&gt;perpendicular&lt;/strong&gt; to the magnetic field. In this case, &lt;strong&gt;sin(&amp;theta;) = 1&lt;/strong&gt;, making the force F = BIL.&lt;/li&gt;
	&lt;li&gt;If the current is parallel or opposite to the magnetic field, the angle &amp;theta; would be 0 degrees or 180 degrees, respectively, and &lt;strong&gt;sin(&amp;theta;) = 0&lt;/strong&gt;, resulting in no force.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;When the current is opposite to the magnetic field&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;In this case, the angle &amp;theta; is 180 degrees.&lt;/li&gt;
		&lt;li&gt;The sine of 180 degrees is 0, so the force experienced by the conductor is zero.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;When the current is parallel to the magnetic field&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Here, the angle &amp;theta; is 0 degrees.&lt;/li&gt;
		&lt;li&gt;The sine of 0 degrees is also 0, leading to no force on the conductor.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;When the current flows at any angle to the magnetic field&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;In this scenario, the angle &amp;theta; can vary between 0 and 90 degrees.&lt;/li&gt;
		&lt;li&gt;The force will be proportional to sin(&amp;theta;), and thus it will be less than the maximum force experienced when the current is perpendicular to the magnetic field.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर यह है कि &lt;u&gt;&lt;strong&gt;जब विद्युत धारा चुंबकीय क्षेत्र के लंबवत होती&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;जब एक विद्युत धारा ले जाने वाला चालक चुंबकीय क्षेत्र में रखा जाता है, तो वह एक बल का अनुभव करता है जिसे &lt;strong&gt;लोरेंत्ज़ बल&lt;/strong&gt; के रूप में जाना जाता है।&lt;/li&gt;
	&lt;li&gt;इस बल का परिमाण सूत्र &lt;strong&gt;F = BIL sin(&amp;theta;)&lt;/strong&gt; द्वारा दिया जाता है, जहाँ &lt;strong&gt;B&lt;/strong&gt; चुंबकीय क्षेत्र की तीव्रता है, &lt;strong&gt;I&lt;/strong&gt; धारा है, &lt;strong&gt;L&lt;/strong&gt; चालक की लंबाई है, और &lt;strong&gt;&amp;theta;&lt;/strong&gt; धारा और चुंबकीय क्षेत्र के बीच का कोण है।&lt;/li&gt;
	&lt;li&gt;बल अधिकतम होता है जब कोण &amp;theta; 90 डिग्री होता है, अर्थात् जब धारा चुंबकीय क्षेत्र के &lt;strong&gt;लंबवत&lt;/strong&gt; होती है। इस स्थिति में, &lt;strong&gt;sin(&amp;theta;) = 1&lt;/strong&gt;, जिससे बल F = BIL होता है।&lt;/li&gt;
	&lt;li&gt;यदि धारा चुंबकीय क्षेत्र के समानांतर या विपरीत है, तो कोण &amp;theta; क्रमशः 0 डिग्री या 180 डिग्री होगा, और &lt;strong&gt;sin(&amp;theta;) = 0&lt;/strong&gt;, जिसके परिणामस्वरूप कोई बल नहीं होगा।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;जब धारा चुंबकीय क्षेत्र के विपरीत होती है&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;इस मामले में, कोण &amp;theta; 180 डिग्री है।&lt;/li&gt;
		&lt;li&gt;180 डिग्री का साइन 0 है, इसलिए चालक द्वारा अनुभव किया जाने वाला बल शून्य है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;जब धारा चुंबकीय क्षेत्र के समानांतर होती है&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;यहाँ, कोण &amp;theta; 0 डिग्री है।&lt;/li&gt;
		&lt;li&gt;0 डिग्री का साइन भी 0 है, जिससे चालक पर कोई बल नहीं लगता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;जब धारा चुंबकीय क्षेत्र से किसी भी कोण पर प्रवाहित होती है&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;इस परिदृश्य में, कोण &amp;theta; 0 और 90 डिग्री के बीच भिन्न हो सकता है।&lt;/li&gt;
		&lt;li&gt;बल sin(&amp;theta;) के समानुपाती होगा, और इस प्रकार यह अधिकतम बल से कम होगा जो तब अनुभव किया जाता है जब धारा चुंबकीय क्षेत्र के लंबवत होती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Sodium&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&lt;strong&gt; element with an electronic configuration of 2,8,1 is Sodium (Na)&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Sodium has an atomic number of 11, which corresponds to the electronic configuration &lt;strong&gt;2,8,1&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;This &lt;strong&gt;means that a sodium atom has 11 electrons, with 2 in the first energy level (1s), 8 in the second energy level&lt;/strong&gt; (2s), and 1 in the third energy level (3s).&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;Sodium is highly reactive because it tends to lose its outermost electron to achieve a stable configuration&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Hydrogen (H)&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;Atomic Number: 1&lt;/li&gt;
		&lt;li&gt;Electronic Configuration: &lt;strong&gt;1&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Hydrogen has only one electron, hence its configuration is &lt;strong&gt;2,0&lt;/strong&gt; (as it has no additional shells beyond the first one).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Chlorine (Cl)&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Atomic Number: 17&lt;/li&gt;
		&lt;li&gt;Electronic Configuration: &lt;strong&gt;2,8,7&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Chlorine has a different outer electron configuration with 7 electrons in its outermost shell.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Magnesium (Mg)&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span id=&quot;cke_bm_53559S&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;Atomic Number: 12&lt;/li&gt;
		&lt;li&gt;Electronic Configuration: &lt;strong&gt;2,8,2&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Magnesium has 2 electrons in its third shell, so its configuration is &lt;strong&gt;2,8,2&lt;/strong&gt;.&lt;span id=&quot;cke_bm_53559E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;सोडियम&lt;/strong&gt;&lt;/u&gt; है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;2,8,1 के इलेक्ट्रॉनिक विन्यास वाला तत्व सोडियम (Na) है&lt;/strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;सोडियम का परमाणु क्रमांक 11 है, जो इलेक्ट्रॉनिक विन्यास &lt;strong&gt;2,8,1&lt;/strong&gt; से मेल खाता है।&lt;/li&gt;
	&lt;li&gt;इसका अर्थ है कि &lt;strong&gt;सोडियम परमाणु में 11 इलेक्ट्रॉन होते हैं, जिसमें पहले ऊर्जा स्तर (1s) में 2, दूसरे ऊर्जा स्तर (2s) में 8 और तीसरे ऊर्जा स्तर (3s) में 1 होता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;सोडियम अत्यधिक अभिक्रियाशील होता है क्योंकि यह एक स्थिर विन्यास प्राप्त करने के लिए अपने सबसे बाहरी इलेक्ट्रॉन को खो देता है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt; &lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;हाइड्रोजन (H)&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;परमाणु क्रमांक: 1&lt;/li&gt;
		&lt;li&gt;इलेक्ट्रॉनिक विन्यास: &lt;strong&gt;1&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;हाइड्रोजन में केवल एक इलेक्ट्रॉन होता है, इसलिए इसका विन्यास &lt;strong&gt;2,0&lt;/strong&gt; है (क्योंकि इसमें पहले कोश के अलावा कोई अतिरिक्त कोश नहीं है)।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;strong&gt;क्लोरीन (Cl)&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;परमाणु क्रमांक: 17&lt;/li&gt;
		&lt;li&gt;इलेक्ट्रॉनिक विन्यास: &lt;strong&gt;2,8,7&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;क्लोरीन का एक अलग बाहरी इलेक्ट्रॉन विन्यास है जिसमें इसके सबसे बाहरी कोश में 7 इलेक्ट्रॉन होते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मैग्नीशियम (Mg)&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;परमाणु क्रमांक: 12&lt;/li&gt;
		&lt;li&gt;इलेक्ट्रॉनिक विन्यास: &lt;strong&gt;2,8,2&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;मैग्नीशियम के तीसरे कोश में 2 इलेक्ट्रॉन होते हैं, इसलिए इसका विन्यास &lt;strong&gt;2,8,2&lt;/strong&gt; है।&lt;span id=&quot;cke_bm_53559E&quot; style=&quot;display: none;&quot;&gt; &lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
